text:
Citation Metrics
Source: Google Scholar

gs = await fetch("citations_gs.json").then(r =&gt; r.json())

// Summary cards
html`
&lt;div style="display:flex; gap:1.5rem; margin-bottom:1.8rem; flex-wrap:wrap;"&gt;
  &lt;div style="background:#002366; color:white; border-radius:8px; padding:1rem 1.8rem; text-align:center;"&gt;
    &lt;div style="font-size:2rem; font-weight:700;"&gt;${gs.total_citations}&lt;/div&gt;
    &lt;div style="font-size:0.82rem; opacity:0.85;"&gt;Total Citations&lt;/div&gt;
  &lt;/div&gt;
  &lt;div style="background:#002366; color:white; border-radius:8px; padding:1rem 1.8rem; text-align:center;"&gt;
    &lt;div style="font-size:2rem; font-weight:700;"&gt;${gs.h_index}&lt;/div&gt;
    &lt;div style="font-size:0.82rem; opacity:0.85;"&gt;h-index&lt;/div&gt;
  &lt;/div&gt;
  &lt;div style="background:#002366; color:white; border-radius:8px; padding:1rem 1.8rem; text-align:center;"&gt;
    &lt;div style="font-size:2rem; font-weight:700;"&gt;${gs.i10_index}&lt;/div&gt;
    &lt;div style="font-size:0.82rem; opacity:0.85;"&gt;i10-index&lt;/div&gt;
  &lt;/div&gt;
&lt;/div&gt;`
